parameters.jsCode:
const session = $('📂 Загрузка сессии').first().json;
const scriptData = $('📄 Загрузка скрипта').first()?.json || {};
const pack = $('🎨 Загрузка стилей').first().json;
const params = $('🔍 Валидация').first().json;

if (!session.video_url) throw new Error('Session has no video URL to compose');

// ─── ASS Time Formatter ───
function toASSTime(seconds) {
  const s = Math.max(0, seconds);
  const h = Math.floor(s / 3600);
  const m = Math.floor((s % 3600) / 60);
  const sec = Math.floor(s % 60);
  const cs = Math.min(99, Math.round((s % 1) * 100));
  return h + ':' + String(m).padStart(2,'0') + ':' + String(sec).padStart(2,'0') + '.' + String(cs).padStart(2,'0');
}

// ─── Generate ASS Subtitles ───
const scriptText = (scriptData.script_text || '').trim();
const durationHint = parseFloat(scriptData.duration_hint) || 40;
const wordsPerLine = params.words_per_line_override || pack.subtitle_words_per_line || 4;

const words = scriptText.split(/\s+/).filter(w => w.length > 0);
const totalWords = words.length;

let dialogues = '';
if (totalWords > 0) {
  let currentTime = 0;
  for (let i = 0; i < totalWords; i += wordsPerLine) {
    const chunk = words.slice(i, Math.min(i + wordsPerLine, totalWords));
    const chunkDur = (chunk.length / totalWords) * durationHint;
    const start = toASSTime(currentTime);
    const end = toASSTime(currentTime + Math.max(chunkDur - 0.05, 0.3));
    let text = chunk.join(' ').replace(/[{}]/g, ' ').replace(/\\/g, ' ').trim();
    const anim = pack.subtitle_animation || 'none';
    if (anim === 'fade') text = '{\\fad(150,150)}' + text;
    else if (anim === 'scale') text = '{\\t(0,200,\\fscx0\\fscy0)\\t(200,400,\\fscx100\\fscy100)}' + text;
    dialogues += 'Dialogue: 0,' + start + ',' + end + ',Default,,0,0,0,,' + text + '\n';
    currentTime += chunkDur;
  }
}

const alignment = pack.subtitle_position === 'top' ? 8 : pack.subtitle_position === 'center' ? 5 : 2;
const boldFlag = (pack.subtitle_bold === true || pack.subtitle_bold === 't' || pack.subtitle_bold === '-1') ? '-1' : '0';
const outline = parseFloat(pack.subtitle_outline) || 2.5;
const shadow  = parseFloat(pack.subtitle_shadow)  || 1.0;
const marginV = parseInt(pack.subtitle_margin_v)   || 80;
const fontSize = parseInt(pack.subtitle_font_size)  || 52;

const assContent = [
  '[Script Info]',
  'ScriptType: v4.00+',
  'PlayResX: 1080',
  'PlayResY: 1920',
  'ScaledBorderAndShadow: yes',
  '',
  '[V4+ Styles]',
  'Format: Name, Fontname, Fontsize, PrimaryColour, SecondaryColour, OutlineColour, BackColour, Bold, Italic, Underline, StrikeOut, ScaleX, ScaleY, Spacing, Angle, BorderStyle, Outline, Shadow, Alignment, MarginL, MarginR, MarginV, Encoding',
  'Style: Default,' + (pack.subtitle_font || 'Arial') + ',' + fontSize + ',' + (pack.subtitle_primary_color || '&H00FFFFFF') + ',&H000000FF,' + (pack.subtitle_outline_color || '&H00000000') + ',' + (pack.subtitle_back_color || '&H80000000') + ',' + boldFlag + ',0,0,0,100,100,0,0,1,' + outline + ',' + shadow + ',' + alignment + ',10,10,' + marginV + ',1',
  '',
  '[Events]',
  'Format: Layer, Start, End, Style, Name, MarginL, MarginR, MarginV, Effect, Text',
  dialogues
].join('\n').trim();

// ─── Build FFmpeg Command ───
const sessionId = session.session_id;
const workDir = '/tmp/compose_' + sessionId;
const outputPath = '/home/node/output/composed_' + sessionId + '_' + pack.pack_id + '.mp4';

const safeVideoUrl = (session.video_url || '').replace(/"/g, '%22');

// Build vf filter chain
const vfParts = [];
if (totalWords > 0) vfParts.push("ass='" + workDir + "/subs.ass'");
const colorFilter = (pack.color_filter || '').trim();
if (colorFilter) vfParts.push(colorFilter);
if (pack.vignette === true || pack.vignette === 't') vfParts.push('vignette');

const vfArg = vfParts.length > 0 ? vfParts.join(',') : null;
const crf = parseInt(pack.output_quality) || 23;

// Base64-encode ASS content to avoid all shell escaping issues
const base64ASS = Buffer.from(assContent, 'utf8').toString('base64');

const cmdLines = [
  'set -e',
  'mkdir -p "' + workDir + '"',
  'wget -q --timeout=300 -O "' + workDir + '/input.mp4" "' + safeVideoUrl + '"'
];

if (totalWords > 0) {
  cmdLines.push('printf "%s" "' + base64ASS + '" | base64 -d > "' + workDir + '/subs.ass"');
}

const ffmpegParts = ['ffmpeg -y -i "' + workDir + '/input.mp4"'];
if (vfArg) ffmpegParts.push('-vf "' + vfArg + '"');
ffmpegParts.push('-c:v libx264 -preset fast -crf ' + crf + ' -c:a copy "' + outputPath + '"');

cmdLines.push(ffmpegParts.join(' '));
cmdLines.push('rm -rf "' + workDir + '"');
cmdLines.push('echo "COMPOSE_DONE:' + outputPath + '"');

return [{ json: {
  command: cmdLines.join('\n'),
  output_path: outputPath,
  session_id: sessionId,
  pack_id: pack.pack_id
}}];

const result = $input.first().json;
const ctx = $('🏗️ Генерация ASS + FFmpeg').first().json;

const stdout = (result.stdout || result.output || '').trim();
const stderr = (result.stderr || '').slice(-1000);

if (!stdout.includes('COMPOSE_DONE')) {
  throw new Error('FFmpeg failed. stderr: ' + stderr);
}

const match = stdout.match(/COMPOSE_DONE:(.+)/);
const finalPath = match ? match[1].trim() : ctx.output_path;

return [{ json: {
  session_id: ctx.session_id,
  final_video_url: finalPath,
  pack_id: ctx.pack_id
}}];
